#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/stat.h>
#include <dirent.h>
#include <time.h>
#include <fcntl.h>

#define MAX_PATH 4096
#define MAX_COMMIT 100
#define MAX_FILES 100
#define MAX_FILE_SIZE 10240

typedef struct {
    char path[MAX_PATH];
    char hash[41];
} FileEntry;

typedef struct {
    char id[41];
    char parent[41];
    char msg[256];
    time_t ts;
    FileEntry files[MAX_FILES];
    int file_count;
} Commit;

int dir_exists(const char *path) {
    struct stat st;
    return stat(path, &st) == 0 && S_ISDIR(st.st_mode);
}

int file_exists(const char *path) {
    struct stat st;
    return stat(path, &st) == 0 && S_ISREG(st.st_mode);
}

void sha1(const char *data, char *out) {
    snprintf(out, 41, "%s", data);
}

void write_file(const char *path, const char *content) {
    FILE *f = fopen(path, "w");
    if (!f) { perror("fopen"); exit(1); }
    fprintf(f, "%s", content);
    fclose(f);
}

char* read_file(const char *path, char *buf, size_t size) {
    FILE *f = fopen(path, "r");
    if (!f) return NULL;
    size_t n = fread(buf, 1, size - 1, f);
    buf[n] = '\0';
    fclose(f);
    return buf;
}

void copy_file(const char *src, const char *dst) {
    char buf[MAX_FILE_SIZE];
    char *content = read_file(src, buf, sizeof(buf));
    if (!content) { perror("read_file"); exit(1); }
    write_file(dst, content);
}

void ensure_dir(const char *path) {
    if (!dir_exists(path)) mkdir(path, 0755);
}

void init() {
    if (dir_exists(".git")) {
        printf("Git repository already exists\n");
        return;
    }
    ensure_dir(".git");
    ensure_dir(".git/objects");
    ensure_dir(".git/refs");
    write_file(".git/HEAD", "");
    write_file(".git/index", "");
    printf("Initialized empty Git repository\n");
}

void hash_object(const char *path) {
    char buf[MAX_FILE_SIZE];
    char *content = read_file(path, buf, sizeof(buf));
    if (!content) { perror("read_file"); exit(1); }
    char hash[41];
    sha1(content, hash);
    char obj_path[MAX_PATH];
    snprintf(obj_path, sizeof(obj_path), ".git/objects/%.2s", hash);
    ensure_dir(obj_path);
    snprintf(obj_path, sizeof(obj_path), ".git/objects/%.2s/%s", hash, hash + 2);
    write_file(obj_path, content);
    printf("%s\n", hash);
}

void update_index(const char *path) {
    char buf[MAX_FILE_SIZE];
    char *content = read_file(path, buf, sizeof(buf));
    if (!content) { perror("read_file"); exit(1); }
    char hash[41];
    sha1(content, hash);
    FILE *idx = fopen(".git/index", "a");
    if (!idx) { perror("fopen index"); exit(1); }
    fprintf(idx, "%s %s\n", hash, path);
    fclose(idx);
}

void add(const char *path) {
    if (!file_exists(path)) {
        fprintf(stderr, "File not found: %s\n", path);
        exit(1);
    }
    hash_object(path);
    update_index(path);
}

void read_index(FileEntry *entries, int *count) {
    *count = 0;
    FILE *idx = fopen(".git/index", "r");
    if (!idx) return;
    char line[MAX_PATH + 50];
    while (fgets(line, sizeof(line), idx)) {
        line[strcspn(line, "\n")] = 0;
        char *space = strchr(line, ' ');
        if (!space) continue;
        *space = 0;
        strcpy(entries[*count].hash, line);
        strcpy(entries[*count].path, space + 1);
        (*count)++;
    }
    fclose(idx);
}

void write_tree(char *tree_hash) {
    FileEntry entries[MAX_FILES];
    int count;
    read_index(entries, &count);
    char tree[MAX_FILE_SIZE] = "";
    for (int i = 0; i < count; i++) {
        char obj_path[MAX_PATH];
        snprintf(obj_path, sizeof(obj_path), ".git/objects/%.2s/%s", entries[i].hash, entries[i].hash + 2);
        char content[MAX_FILE_SIZE];
        read_file(obj_path, content, sizeof(content));
        strcat(tree, entries[i].hash);
        strcat(tree, " ");
        strcat(tree, entries[i].path);
        strcat(tree, "\n");
    }
    sha1(tree, tree_hash);
    char obj_path[MAX_PATH];
    snprintf(obj_path, sizeof(obj_path), ".git/objects/%.2s", tree_hash);
    ensure_dir(obj_path);
    snprintf(obj_path, sizeof(obj_path), ".git/objects/%.2s/%s", tree_hash, tree_hash + 2);
    write_file(obj_path, tree);
}

void commit(const char *msg) {
    char tree_hash[41];
    write_tree(tree_hash);
    char parent[41] = "";
    if (file_exists(".git/HEAD")) {
        char head[41];
        char buf[64];
        if (read_file(".git/HEAD", buf, sizeof(buf))) {
            buf[strcspn(buf, "\n")] = 0;
            strcpy(parent, buf);
        }
    }
    char commit_str[MAX_FILE_SIZE];
    snprintf(commit_str, sizeof(commit_str), "tree %s\nparent %s\n%s\n%ld\n", tree_hash, parent, msg, time(NULL));
    char commit_hash[41];
    sha1(commit_str, commit_hash);
    char obj_path[MAX_PATH];
    snprintf(obj_path, sizeof(obj_path), ".git/objects/%.2s", commit_hash);
    ensure_dir(obj_path);
    snprintf(obj_path, sizeof(obj_path), ".git/objects/%.2s/%s", commit_hash, commit_hash + 2);
    write_file(obj_path, commit_str);
    write_file(".git/HEAD", commit_hash);
    printf("Committed %s\n", commit_hash);
}

void log_commits() {
    char head[41];
    char buf[64];
    if (!read_file(".git/HEAD", buf, sizeof(buf))) {
        printf("No commits yet\n");
        return;
    }
    buf[strcspn(buf, "\n")] = 0;
    strcpy(head, buf);
    while (strlen(head) > 0) {
        char obj_path[MAX_PATH];
        snprintf(obj_path, sizeof(obj_path), ".git/objects/%.2s/%s", head, head + 2);
        char commit_str[MAX_FILE_SIZE];
        if (!read_file(obj_path, commit_str, sizeof(commit_str))) break;
        char *p = strstr(commit_str, "parent ");
        char parent[41] = "";
        if (p) {
            p += 7;
            sscanf(p, "%40s", parent);
        }
        p = strstr(commit_str, "\n") + 1;
        p = strstr(p, "\n") + 1;
        char *msg = p;
        p = strstr(msg, "\n");
        *p = 0;
        printf("commit %s %s\n", head, msg);
        strcpy(head, parent);
    }
}

void load_commit(const char *hash, Commit *c) {
    strcpy(c->id, hash);
    char obj_path[MAX_PATH];
    snprintf(obj_path, sizeof(obj_path), ".git/objects/%.2s/%s", hash, hash + 2);
    char commit_str[MAX_FILE_SIZE];
    read_file(obj_path, commit_str, sizeof(commit_str));
    char *p = strstr(commit_str, "tree ");
    p = strstr(p + 5, "\n") + 1;
    p = strstr(p, "parent ");
    if (p) {
        p += 7;
        sscanf(p, "%40s", c->parent);
    } else {
        strcpy(c->parent, "");
    }
    p = strstr(p, "\n") + 1;
    char *msg = p;
    p = strstr(msg, "\n");
    *p = 0;
    strcpy(c->msg, msg);
    p = strstr(p + 1, "\n") + 1;
    sscanf(p, "%ld", &c->ts);
    c->file_count = 0;
    snprintf(obj_path, sizeof(obj_path), ".git/objects/%.2s/%s", commit_str + 5, (commit_str + 5) + 2);
    read_file(obj_path, commit_str, sizeof(commit_str));
    p = strtok(commit_str, "\n");
    while (p) {
        char *space = strchr(p, ' ');
        if (space) {
            *space = 0;
            strcpy(c->files[c->file_count].hash, p);
            strcpy(c->files[c->file_count].path, space + 1);
            c->file_count++;
        }
        p = strtok(NULL, "\n");
    }
}

void checkout(const char *hash) {
    Commit c;
    load_commit(hash, &c);
    for (int i = 0; i < c.file_count; i++) {
        char obj_path[MAX_PATH];
        snprintf(obj_path, sizeof(obj_path), ".git/objects/%.2s/%s", c.files[i].hash, c.files[i].hash + 2);
        char content[MAX_FILE_SIZE];
        read_file(obj_path, content, sizeof(content));
        write_file(c.files[i].path, content);
    }
    write_file(".git/index", "");
    for (int i = 0; i < c.file_count; i++) {
        update_index(c.files[i].path);
    }
}

void reset(const char *hash) {
    checkout(hash);
    write_file(".git/HEAD", hash);
}

int main(int argc, char *argv[]) {
    if (argc < 2) {
        fprintf(stderr, "Usage: %s <command>\n", argv[0]);
        return 1;
    }
    if (strcmp(argv[1], "init") == 0) {
        init();
    } else if (strcmp(argv[1], "hash-object") == 0) {
        if (argc < 3) { fprintf(stderr, "Usage: %s hash-object <file>\n", argv[0]); return 1; }
        hash_object(argv[2]);
    } else if (strcmp(argv[1], "add") == 0) {
        if (argc < 3) { fprintf(stderr, "Usage: %s add <file>\n", argv[0]); return 1; }
        add(argv[2]);
    } else if (strcmp(argv[1], "commit") == 0) {
        if (argc < 3 || strcmp(argv[2], "-m") != 0 || argc < 4) {
            fprintf(stderr, "Usage: %s commit -m <message>\n", argv[0]);
            return 1;
        }
        commit(argv[3]);
    } else if (strcmp(argv[1], "log") == 0) {
        log_commits();
    } else if (strcmp(argv[1], "checkout") == 0) {
        if (argc < 3) { fprintf(stderr, "Usage: %s checkout <commit>\n", argv[0]); return 1; }
        checkout(argv[2]);
    } else if (strcmp(argv[1], "reset") == 0) {
        if (argc < 3) { fprintf(stderr, "Usage: %s reset <commit>\n", argv[0]); return 1; }
        reset(argv[2]);
    } else {
        fprintf(stderr, "Unknown command: %s\n", argv[1]);
        return 1;
    }
    return 0;
}
